                                                        {{ $t('SelectSetup') }}:<span style="color: #dc3545;">*</span>
                                                    </label>
                                                    <select v-model="setupId" class="form-control" :class="{ 'is-invalid': showError && !setupId }" style="flex: 0.5;" @change="handleSetupChange">
                                                            <option value="" disabled>Select</option>
                                                            <option v-for="itm in setupList || []" :key="itm.value" :value="itm.value">
                                                                {{ itm.name }}
                                                            </option>
                                                    </select>
                                                    <div class="invalid-feedback text-danger small"
                                                        v-if="showError && !setupId">
                                                        {{ $t('MandatoryFieldSetup') }}
                                                    </div>
                                                 </div>
                                            </div>
                                            <div class="col-md-4">
                                                <div class="form-group mb-4">
                                                    <label >
                                                        {{ $t('ServiceName') }}:<span style="color: #dc3545;">*</span>
                                                    </label>
                                                    <input v-model="conditionName" :disabled="isEditMode" :class="['form-control', { 'is-invalid': showError && !conditionName }]" placeholder="Enter service name" required />
                                                    <div class="invalid-feedback text-danger small"
                                                        v-if="showError && !conditionName">
                                                        {{ $t('MandatoryFieldConditionName') }}
                                                    </div>
                                                 </div>
                                            </div>
                                            
                                        </div>
                                        <!-- Condition Logic Display -->
                                        <div class="form-group mb-4">
                                            <label >Condition Logic:</label>
                                            <div class="noneditablefield">
                                                {{ conditionText }}
                                            </div>
