                                                            <option v-for="option in groupedOptions" :key="option.value" :value="option.value" >
                                                                {{ $t(option.label) }}
                                                            </option>
                                                        </select>
                                                        
                                                        <select v-model="row.operator" class="form-control" :class="{ 'is-invalid': showValidationErrors && !row.operator  }" style="flex: 0.5;" :disabled="isEditMode" @change="handleOperatorChange(row)">
