                                                                        <option v-for="itm in getFilteredOperators(row)" :key="itm.OPERATOR_ID" :value="itm.OPERATOR_ID">
                                                                            {{ itm.OPERATOR_DISPLAY_NAME }}
                                                                        </option>
                                                                </select>

                                                            </div>
                                                           
                                                            <div v-if="row.sqlType === 'datetime' && !isValueHidden(row) && !isShowIsWeekDay(row) && !row.isIntervalOperator" 
                                                                 class="d-flex align-items-center mr-2">
                                                                <div class="custom-control custom-radio custom-control-inline mr-3">
                                                                    <input type="radio" 
                                                                           class="custom-control-input" 
                                                                           :id="`datetime-date-${blockIndex}-${i}`"
                                                                           value="date"
                                                                           v-model="row.datetimeMode"
                                                                           @change="onDatetimeModeChange(row, 'date')"
                                                                           :disabled="isEditMode" />
                                                                    <label class="custom-control-label" 
                                                                           :for="`datetime-date-${blockIndex}-${i}`">Date</label>
                                                                </div>
                                                                <div class="custom-control custom-radio custom-control-inline">
