                                                                :disabled="isEditMode"
                                                                :type="isNumberType(row) ? 'number' : 'text'"
                                                                v-on="isNumberType(row) ? { input: event => filterNumberInput(row, 'value', event) } : {}"
                                                                :class="{ 'is-invalid': showValidationErrors && (row.valueTo === null || row.valueTo === undefined || row.valueTo === '') }" 
                                                                placeholder="Value"/>
                                                        </div>
