                                                                            <input class="form-check-input custom-control-input dynamic" type="checkbox" id="peakHoursSwitch" v-model="form.rateToggle" @change="fncApplyRate" :disabled="currentMode === 'View'" />
                                                                            <span class="slider round" style="cursor: default;">
                                                                                <span class="slider-yes">{{ $t('Yes') }}</span>
                                                                                <span class="slider-no">{{ $t('No') }}</span>
                                                                            </span>
                                                                        </label>
                                                                    </div>
                                                                </div>
                                                        </div>
                                                        <div class="input-group mt-3" v-if="form.rateToggle">
                                                            <span>
                                                             <label class="form-check form-check-inline">
                                                                <div class="custom-control custom-radio custom-control-inline">
                                                                    <input type="radio" v-model="form.isLeaf" :value="true" @change="chkisLeafRule" class="custom-control-input" :disabled="currentMode === 'View'" />
                                                                    <label for="IsLeafNode" class="custom-control-label" v-if="isBillingType">{{ $t('DirectWorkCode') }}</label>
                                                                    <label for="Fixed" class="custom-control-label" v-else>{{ $t('Fixed') }}</label>
                                                                </div>
                                                                </label>
                                                          <label class="form-check form-check-inline" v-if="!isGlobalCategorySelected">
                                                            <div class="custom-control custom-radio custom-control-inline">
                                                                <input type="radio" id="usageBasedRate" :value="true" v-model="form.addAdder" @change="onAdderChecked" class="custom-control-input" :disabled="currentMode === 'View'" />
                                                                <label for="AddAdder" class="custom-control-label" v-if="isBillingType">{{ $t('AddAdder') }}</label>
                                                                <label for="UsageBased" class="custom-control-label" v-else>{{ $t('UsageBased') }}</label>
                                                            </div>
                                                        </label>
                                                            </span>
                                                        </div>
                                                    </div>

