                                                    <div class="col-12 d-flex p-0" v-if="isShowServiceDetail && form.rateToggle">
                                                        <div class="col-lg-4" v-if="showIsLeafFlag">
                                                            <div class="form-group">
                                                                <label>{{ $t('ClientServiceFlag') }}:</label><br>
                                                                <div class="flag-selector">
                                                                    <span @click="isLeafTogglePopup" class="flag-icon" :style="{ color: form.selectedFlag.color }">
                                                                        <i class="fas fa-flag"></i>
                                                                    </span>

