                                                                    <div v-if="form.showPopup" class="popup">
                                                                        <div class="popup-header">
                                                                            <span>Flag Condition</span>
                                                                            <button @click="form.showPopup = false" class="close-btn">×</button>
                                                                        </div>
                                                                        <div class="flags">
                                                                            <span v-for="flag in flags" :key="flag.value" class="flag-option" @click="isLeafSelectFlag(flag)" :style="{ color: flag.color }">
                                                                                <i class="fas fa-flag"></i>
                                                                            </span>
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </div>
