                                                                    <option v-for="itm in workCodeList" :key="itm.value" :value="itm.value">{{ itm.name }}</option>
                                                                </select>
                                                            </div>
                                                        </div>
                                                    </div>

                                                    <div class="col-12 d-flex flex-wrap p-0"
                                                        v-if="isShowServiceDetail && form.rateToggle">
