        handleBuilderClick(event) {
            // If user already confirmed, allow normal behavior without showing modal
            if (this.hasRuleConfirmation) {
                return; // Allow all clicks to work normally
            }

            // If alert modal is active, block to prevent multiple modals
            if (this.openRuleMode) {
                event.preventDefault();
                event.stopPropagation();
                return;
            }

            const fieldTags = ['INPUT', 'SELECT', 'TEXTAREA'];
            // Only process if it's a field click and conditions are met
            if (fieldTags.includes(event.target.tagName)) {
                // Save original field values before showing modal
                this.saveOriginalFieldValues();
                
                // Show the alert modal
                if (this.reqFrom === "fromBillingService" && 
