        toggleDay(row, dayValue) {
            let current = (row.daysOfWeek || "").split(',').filter(Boolean);
            const index = current.indexOf(dayValue);

            if (index >= 0) {
                current.splice(index, 1); // uncheck
            } else {
                current.push(dayValue); // check
            }

            row.daysOfWeek = current.join(',');
        },
        isMultiSelectOperator(row) {
            const selectedOperator = (row.operatorList || []).find(op => op.OPERATOR_ID === row.operator);
            if (!selectedOperator) return false;
            const name = selectedOperator.OPERATOR_DISPLAY_NAME?.toLowerCase();
            return name === 'equal to one of multiple possible values' || name === 'not equal to one of multiple possible values';
        },
        isValueHidden(row) {
            const selectedOperator = (row.operatorList || []).find(
                op => op.OPERATOR_ID === row.operator
            );
            if (!selectedOperator) return false;

            const operatorName = selectedOperator.OPERATOR_DISPLAY_NAME?.toLowerCase();
            return ['is empty','is not empty','is off day','is duplicate','is highest','is lowest','is not highest','is not lowest'].includes(operatorName);
            // return operatorName === 'is empty' || operatorName === 'is not empty' || operatorName === 'is off day' || operatorName === 'is duplicate' ;
        },
        isIntervalValueHidden(row) {
            const selectedOperator = (row.operatorList || []).find(
                op => op.OPERATOR_ID === row.additionalOperatorId
            );
            if (!selectedOperator) return false;

            const operatorName = selectedOperator.OPERATOR_DISPLAY_NAME?.toLowerCase();
            return ['is empty','is not empty','is off day','is duplicate','is highest','is lowest','is not highest','is not lowest'].includes(operatorName);
            // return operatorName === 'is empty' || operatorName === 'is not empty' || operatorName === 'is off day' || operatorName === 'is duplicate' ;
        },
        isShowIsWeekDay(row) {
            const selectedOperator = (row.operatorList || []).find(
                op => op.OPERATOR_ID === row.operator
            );
            if (!selectedOperator) return false;

            const operatorName = selectedOperator.OPERATOR_DISPLAY_NAME?.toLowerCase();
            return operatorName === 'is week end' || operatorName === 'is working day';
