                            operatorList = operatorRes || [];
                        }
                        // if (selectedOption) {
                        //     if (!this.allOperatorList || this.allOperatorList.length === 0) {
                        //         await this.GetOperators();
                        //     }
                            
                        //     let operatorRes = this.allOperatorList.filter(op => op.OPERATION_DATA_TYPE.includes(selectedOption.sqlType))
                        //     if (!operatorRes.some(op => op.OPERATOR_ID === item.OPERATOR_ID) && item.OPERATOR_ID) {
                        //         const missingOp = this.allOperatorList.find(op => op.OPERATOR_ID === item.OPERATOR_ID);
                        //         if (missingOp) operatorRes.push(missingOp);
                        //     }
                        //     operatorList = operatorRes || [];
                        // }
                        if(selectedOption.sqlType == 'select' && (selectedOption.picklistOptions).toLowerCase() != "lookup"){
                            if (selectedOption.picklistOptions && selectedOption.picklistOptions.trim() !== '') {
                                const selectOptions = selectedOption.picklistOptions.split(',').map(option => ({
                                        first_value : null,
                                        name: option.trim(), 
                                        value: option.trim().replace(/\s+/g, '-'),
                                        second_value : null
                                    }));
                                valueOptions = selectOptions;
                                const operatorMeta = operatorList.find(op => op.OPERATOR_ID === item.OPERATOR_ID);
                                const multiSelectOperators = ['equal to one of multiple possible values', 'not equal to one of multiple possible values'];
                                const isMultiSelect = operatorMeta && multiSelectOperators.includes(operatorMeta.OPERATOR_DISPLAY_NAME?.toLowerCase());
                                if (isMultiSelect) {
                                    const valueIds = parsedValue.split(',').map(v => v.trim());
                                    parsedValue = valueOptions.filter(opt => valueIds.includes(String(opt.value)));
                                } else {
                                    const matched = valueOptions.find(opt => String(opt.value) === String(parsedValue));
                                    parsedValue = (matched && matched.value !== undefined) ? matched.value : parsedValue;
                                }
                            }
                        }
                        else if(sqlType === 'select' && (selectedOption.picklistOptions).toLowerCase() == "lookup") {
                            const ddlRes = await DataService.GetDDLData(`id=&moduleName=&type=${selectedOption.fieldCode}&search=`);
                            valueOptions = ddlRes?.data?.DATA || [];
                            const operatorMeta = operatorList.find(op => op.OPERATOR_ID === item.OPERATOR_ID);
                            const multiSelectOperators = ['equal to one of multiple possible values', 'not equal to one of multiple possible values'];
                            const isMultiSelect = operatorMeta && multiSelectOperators.includes(operatorMeta.OPERATOR_DISPLAY_NAME?.toLowerCase());

                            if (isMultiSelect) {
                                const valueIds = parsedValue.split(',').map(v => v.trim());
                                parsedValue = valueOptions.filter(opt => valueIds.includes(String(opt.value)));
                            } else {
                                const matched = valueOptions.find(opt => String(opt.value) === String(parsedValue));
                                parsedValue = (matched && matched.value !== undefined) ? matched.value : parsedValue;
                            }
                        }
                        else if (sqlType === 'bool') {
                            var radioValue = vm.MakeArray(selectedOption.picklistOptions, 'radio');
                            if (radioValue.length > 0) {
                                valueOptions = radioValue;
                            }
                        } 
                        else if (!isNaN(parsedValue) && parsedValue !== '') {
                            parsedValue = Number(parsedValue);
                        }
                        
                        // Determine datetimeMode for datetime fields based on original value format
                        let datetimeMode = 'date'; // default
                        if (sqlType === 'datetime') {
                            // Check the original FIRST_VALUE format from database
                            const originalValue = item.FIRST_VALUE ? String(item.FIRST_VALUE).trim() : '';
                            
                            if (originalValue) {
                                // Time patterns: HH:mm, HH:mm:ss, HH:mm AM/PM, etc.
                                const timePatterns = [
                                    /^(\d{1,2}):(\d{2})(\s*(AM|PM))?$/i,           // HH:mm or HH:mm AM/PM
                                    /^(\d{1,2}):(\d{2}):(\d{2})(\s*(AM|PM))?$/i,   // HH:mm:ss or HH:mm:ss AM/PM
                                    /^(\d{1,2}):(\d{2}):(\d{2})\.\d+$/i            // HH:mm:ss.milliseconds
                                ];
                                
                                // Check if original value matches time-only patterns
                                const isTimePattern = timePatterns.some(pattern => pattern.test(originalValue));
                                
                                if (isTimePattern) {
                                    datetimeMode = 'time';
                                } else {
                                    // Check if it has date separators (/, -, .) or year (4 digits)
                                    const hasDateSeparators = /[\/\-\.]/.test(originalValue);
                                    const hasYear = /\d{4}/.test(originalValue);
                                    
                                    // If it has date separators or year, it's a date
                                    // If it's a short string (<=8 chars) starting with time pattern, it's time
                                    if (hasDateSeparators || hasYear || originalValue.length > 10) {
                                        datetimeMode = 'date';
                                    } else if (originalValue.length <= 8 && /^\d{1,2}:\d{2}/.test(originalValue)) {
                                        datetimeMode = 'time';
                                    } else {
                                        datetimeMode = 'date';
                                    }
                                }
                                
                                // Also check SECOND_VALUE (valueTo) for "between" operators
                                if (item.SECOND_VALUE) {
                                    const valueToStr = String(item.SECOND_VALUE).trim();
                                    const isValueToTime = timePatterns.some(pattern => pattern.test(valueToStr));
                                    if (isValueToTime) {
                                        datetimeMode = 'time';
                                    }
                                }
                            }
                        }
                        return {
                            relation: item.RELATION_WITH_PARENT || '',
                            openingBracket: item.OPENING_BRACKETS || '',
                            field: item.TEMPLATE_ID || '',
                            operator: item.OPERATOR_ID || '',
                            value: parsedValue,
                            valueTo: valueTo,
                            daysOfWeek: item.DaysofTheWeek,
                            closingBracket: item.CLOSING_BRACKETS || '',
                            operatorList: operatorList,
                            valueOptions: valueOptions,
                            sqlType: sqlType, // Pass SQL type to row for conditional rendering
                            datetimeMode: datetimeMode,
                            additionalOperatorId:item.ADDITIONAL_OPERATOR_ID,
                            additionalTemplateId : item.ADDITIONAL_TEMPLATE_ID,
                            isIntervalOperator : item.ADDITIONAL_TEMPLATE_ID ? true :false
                        };
                    })
                );
                vm.syncConditionBlocks();
                // vm.isLoading = false;
            }
        },
