        validateAdditionalField(row) {
            if (row.field && row.additionalTemplateId && row.field === row.additionalTemplateId){
                this.ShowAlert('Please select different field.', "warning", this.$t("Alert"));
                row.additionalTemplateId = '';
            }
            const allOptions = Object.values(this.groupedOptions).flat();
            const selectedOption = allOptions.find(opt => opt.value === row.additionalTemplateId);
            if (!selectedOption) return;
            this.$set(row, 'value', '');
            this.$set(row, 'valueTo', '');
            // ✅ override sqlType
            this.$set(row, 'sqlType', selectedOption.sqlType);
        },
        validateAdditionalOperators(row) {
            if (row.operator && row.additionalOperatorId && row.operator === row.additionalOperatorId){
                this.ShowAlert('Please select different Operator.', "warning", this.$t("Alert"));
                row.additionalOperatorId = '';
            }
        },
        getFilteredOperators(row) {
            const baseList = row.operatorList || [];
            const selectedOp = baseList.find(
                o => o.OPERATOR_ID === row.operator
            );
            const expr = selectedOp?.OPERATOR_EXPRESSION?.toUpperCase() || '';
            const compareOps = ['=', '<', '>', '>=', '<='];
            // HAS WITH → exclude comparison operators
            if (expr.includes('HAS WITH')) {
                return baseList.filter(
                    op => !compareOps.includes(op.OPERATOR_EXPRESSION)
                );
            }
            // DIFF → include ONLY comparison operators
            if (expr.includes('DIFF')) {
                return baseList.filter(
                    op => compareOps.includes(op.OPERATOR_EXPRESSION)
                );
            }
            // default → show all
            return baseList;
        },
        getAdditionalFieldOptions(row) {
            const op = row.operatorList?.find(
                o => o.OPERATOR_ID === row.operator
            );
            const expr = op?.OPERATOR_EXPRESSION?.toUpperCase() || '';
            const options = Array.isArray(this.groupedOptions)
                ? this.groupedOptions
                : Object.values(this.groupedOptions).flat();
            if (expr.includes('HAS WITH')) {
                return options.filter(
                    o => o.sqlType !== 'date' && o.sqlType !== 'datetime'
                );
            }
            if (expr.includes('DIFF')) {
                return options.filter(
                    o => o.sqlType === 'date' || o.sqlType === 'datetime'
                );
            }
            return options;
        },
        handleFieldChange: function (row) {
            // Reset validation errors when user starts editing
            this.showValidationErrors = false;
            
            const allOptions = Object.values(this.groupedOptions).flat();
            const selectedOption = allOptions.find(opt => opt.value === row.field);
            if (!selectedOption) return;

            this.$set(row, 'isIntervalOperator', false);
            this.$set(row, 'operator', '');
            this.$set(row, 'value', '');
            this.$set(row, 'valueTo', '');
            this.$set(row, 'operatorList', []);
            this.$set(row, 'sqlType', selectedOption.sqlType);

            if (selectedOption.sqlType === 'datetime') {
                this.$set(row, 'datetimeMode', row.datetimeMode || 'date');
            } else {
                this.$delete(row, 'datetimeMode');
            }
            const json = this.allOperatorList.filter(op => op.OPERATION_DATA_TYPE.includes(selectedOption.sqlType))
            if (json != null) 
            {
                this.$set(row, 'operatorList', json);
            }
            // const url = "templateId=" + selectedOption.value;
            // DataService.GetOperators(url).then((response) => {
            //     const json = response.data;
            //     if (json != null) {
            //         this.$set(row, 'operatorList', json);
            //     }
            // });
        },
        GetOperators :function(){
            const url = "templateId=";
            DataService.GetOperators(url).then((response) => {
                const json = response.data;
                if (json != null) {
                    this.allOperatorList = json;
                }
            });
        },
        isIntervalOperator(operatorId, operatorList) {
            if (!operatorId || !operatorList?.length) return false;
            const operator = operatorList.find(
                op => op.OPERATOR_ID === operatorId
            );
            if (!operator) return false;
            const expr = operator.OPERATOR_EXPRESSION?.toUpperCase() || '';
            return expr.includes('DIFF') || expr.includes('HAS WITH');
        },
        handleOperatorChange: function (row) {
            var vm = this;
            this.$set(row, 'isIntervalOperator', false);
            this.$set(row, 'additionalTemplateId', '');
            this.$set(row, 'additionalOperatorId', '');
            this.$set(row, 'sqlType', '');
            this.$set(row, 'valueOptions', []);
            this.$set(row, 'value', '');
            this.$set(row, 'valueTo', '');
            this.$set(row, 'daysOfWeek', '');
            const allOptions = Object.values(this.groupedOptions).flat();
            const selectedOption = allOptions.find(opt => opt.value === row.field);
            if (!selectedOption) return;
            const isInterval = this.isIntervalOperator(row.operator, row.operatorList); 
            this.$set(row, 'isIntervalOperator', isInterval);
            this.$set(row, 'sqlType', selectedOption.sqlType);
            if (selectedOption.sqlType == 'select' && (selectedOption.picklistOptions).toLowerCase() != "lookup") {
                if (selectedOption.picklistOptions && selectedOption.picklistOptions.trim() !== '') {
                    const dropValue = selectedOption.picklistOptions.split(',').map(option => ({
                        first_value: null,
                        name: option.trim(),
                        value: option.trim().replace(/\s+/g, '-'),
                        second_value: null
                    }));
                    this.$set(row, 'valueOptions', dropValue);
                }
            } else if (selectedOption.sqlType == 'select' && (selectedOption.picklistOptions).toLowerCase() == "lookup") {
                var params = `id=&moduleName=&type=${selectedOption.fieldCode}&search=`;
                DataService.GetDDLData(params).then((response) => {
                    if (response.data) {
                        var json = response.data;
                        if (json != null) {
                            this.$set(row, 'valueOptions', response.data.DATA);
                        }
                    }
                });
            } else if (selectedOption.sqlType == 'bool') {
                var radioValue = vm.MakeArray(selectedOption.picklistOptions, 'radio');
                if (radioValue.length > 0) {
                    this.$set(row, 'valueOptions', radioValue);
                }
            }
        },
        filterNumberInput(row, field) {
            if (!row.numberMode) return;
            if (row.numberMode === 'integer') {
                row[field] = row[field].replace(/[^0-9]/g, '');
            } 
            else if (row.numberMode === 'decimal') {
                row[field] = row[field]
                    .replace(/[^0-9.]/g, '')
                    .replace(/(\..*)\./g, '$1');
            }
        },
