        onRuleYes() {
            // Close modal and set confirmation flag so alert won't show again
            // Allow field values to remain as they are
            this.openRuleMode = false;
            this.hasRuleConfirmation = true;
            
            // Execute pending delete action if any
            if (this.pendingDeleteAction) {
                const action = this.pendingDeleteAction;
                this.pendingDeleteAction = null; // Clear pending action
                
                if (action.actionType === 'removeBlock') {
                    // Execute remove block
                    if (this.conditionBlocks.length > 1) {
                        this.conditionBlocks.splice(action.blockIndex, 1);
                    }
                } else if (action.actionType === 'removeCondition') {
                    // Execute remove condition
                    this.conditionBlocks[action.blockIndex].conditions.splice(action.conditionIndex, 1);
                }
            }
        },
        onConditionBuilderClick() {
            // Only trigger the rule popup flow when coming from Billing Service
            if (this.reqFrom === "fromBillingService" && this.sCount !== 0) {
                if (this.hasRuleConfirmation) {
                    return;
                }
                if (
                    Number(this.conditionId) > 0 &&
                    Array.isArray(this.getRuleConditions) &&
                    this.getRuleConditions.length > 0 &&
                    this.reqFrom === "fromBillingService"
                ) {
                    this.openRuleMode = true;
                } 
            }
        },
        validateConditions() {
            // Validate conditionBlocks instead of form.conditions
            if (!this.conditionBlocks || this.conditionBlocks.length === 0) {
                return false;
            }

            return this.conditionBlocks.every(block => {
                if (!block.conditions || block.conditions.length === 0) {
                    return false;
                }

                return block.conditions.every(row => {
                    // 1️⃣ Required base fields
                    if (!row.field || !row.operator) {
                        return false;
                    }

                    // 2️⃣ Interval operator validation
                    if (row.isIntervalOperator) {
                        if (!row.additionalTemplateId) {
                            return false;
                        }

                        if (!row.additionalOperatorId) {
                            return false;
                        }

                        // allow 0 but not empty
                        if (row.value === null || row.value === undefined || row.value === '') {
                            return false;
                        }

                        return true;
                    }

                    // 3️⃣ Datetime mode required
                    if (row.sqlType === 'datetime' && !row.datetimeMode) {
                        return false;
                    }

                    // 4️⃣ Weekday validation
                    // if (this.isShowIsWeekDay(row)) {
                    //     if (!Array.isArray(row.daysOfWeek) || row.daysOfWeek.length === 0) {
                    //         return false;
                    //     }
                    //     return true;
                    // }

                    // 5️⃣ Value validation
                    if (!this.isValueHidden(row)) {
                        // multiselect operator
                        if (Array.isArray(row.value)) {
                            if (row.value.length === 0) {
                                return false;
                            }
                        }
                        // normal input (allow 0)
                        // else if (row.value === null || row.value === undefined || row.value === '') {
                        //     return false;
                        // }
                    }

