        // Sync conditionBlocks with form.conditions for backward compatibility
        syncConditionBlocks() {
            if (!(this.form.conditions && this.form.conditions.length > 0)) {
                return;
            }
           
            const blocks = [];
            let currentBlock = null;
            let pendingJoinWithPrevious = '';

            const pushCurrentBlockIfAny = () => {
                if (currentBlock && currentBlock.conditions.length > 0) {
                    // Decide intra-block operator based on relations recorded inside the block (after the first condition)
                    const intraRelations = (currentBlock._relations || [])
                        .filter(r => r && r.trim() !== '')
                        .map(r => r.toUpperCase());
                    if (intraRelations.length > 0) {
                        currentBlock.operator = intraRelations[0];
                    } else {
                        currentBlock.operator = currentBlock.operator || 'AND';
                    }
                    delete currentBlock._relations;
                    blocks.push(currentBlock);
                }
            };

            this.form.conditions.forEach((condition, index) => {
                const opening = (condition.openingBracket || '').toString();
                const closing = (condition.closingBracket || '').toString();
                const relation = (condition.relation || '').toString().toUpperCase();

                const hasOpening = opening.includes('(');
                const hasClosing = closing.includes(')');

                // Start a new block when we encounter an opening bracket or if no block exists yet
                if (hasOpening || !currentBlock) {
                    // Push previous block if it exists
                    pushCurrentBlockIfAny();

                    currentBlock = {
                        operator: 'AND',
                        joinWithPrevious: blocks.length > 0 ? (pendingJoinWithPrevious || 'OR') : '',
                        conditions: [],
                        _relations: []
                    };

                    // The relation on the first condition in a block represents the join with previous block
                    pendingJoinWithPrevious = relation || pendingJoinWithPrevious;
                }

                // Add current condition to the block
                currentBlock.conditions.push({
                    field: condition.field || '',
                    operator: condition.operator || '',
                    value: condition.value,
                    valueTo: condition.valueTo,
                    daysOfWeek: condition.daysOfWeek || '',
                    operatorList: condition.operatorList || [],
                    valueOptions: condition.valueOptions || [],
                        sqlType: condition.sqlType || '',
                        datetimeMode: condition.sqlType === 'datetime'
                            ? (condition.datetimeMode || this.inferDatetimeModeFromValues(condition.value, condition.valueTo))
                            : (condition.datetimeMode || 'date'),
                              additionalOperatorId:condition.additionalOperatorId,
               additionalTemplateId : condition.additionalTemplateId,
                   isIntervalOperator : condition.isIntervalOperator
                });

                // Record intra-block relation (relation between previous and this condition)
                if (currentBlock.conditions.length > 1) {
                    currentBlock._relations.push(relation);
                }

                // Close the block when encountering a closing bracket
                if (hasClosing) {
                    // Assign the joinWithPrevious for this block using the first condition's relation stored earlier
                    currentBlock.joinWithPrevious = blocks.length > 0 ? (pendingJoinWithPrevious || 'OR') : '';
                    // After closing, reset pending join for the next block
                    pendingJoinWithPrevious = '';
                    pushCurrentBlockIfAny();
                    currentBlock = null;
                }
            });

            // In case the last block didn't explicitly close with a ')' but has conditions
            pushCurrentBlockIfAny();

            // Fallback: if nothing parsed into blocks, keep a single block
            if (blocks.length === 0) {
                this.conditionBlocks = [
                    {
                        operator: 'AND',
                        joinWithPrevious: '',
                        conditions: this.form.conditions.map(condition => ({
                            field: condition.field || '',
                            operator: condition.operator || '',
                            value: condition.value,
                            valueTo: condition.valueTo,
                            daysOfWeek: condition.daysOfWeek || '',
                            operatorList: condition.operatorList || [],
                            valueOptions: condition.valueOptions || [],
                            sqlType: condition.sqlType || '',
                            datetimeMode: condition.datetimeMode || 'date',
                            additionalOperatorId:condition.additionalOperatorId,
               additionalTemplateId : condition.additionalTemplateId,
                   isIntervalOperator : condition.isIntervalOperator
                        }))
                    }
                ];
            } else {
                this.conditionBlocks = blocks;
            }
        },
