        // Sync form.conditions with conditionBlocks for saving
        syncFormConditions() {
            this.form.conditions = [];
            this.conditionBlocks.forEach((block, blockIndex) => {
                block.conditions.forEach((condition, conditionIndex) => {
                    const selectedOperator = (condition.operatorList || []).find(op => op.OPERATOR_ID === condition.operator);
                    const operatorDisplay = selectedOperator ? selectedOperator.OPERATOR_DISPLAY_NAME : condition.operator;
                    const operatorName = operatorDisplay?.toLowerCase();
                    const operators = ['is empty','is not empty','is off day','is duplicate','is highest','is lowest','is not highest','is not lowest','has with','is working day','is week end'];
                    if(operators.includes(operatorName)){
                        if (condition.field &&  condition.operator){
                            this.form.conditions.push({
                                relation: conditionIndex > 0 ? block.operator : (blockIndex > 0 ? (block.joinWithPrevious || 'OR') : ''),
                                openingBracket: blockIndex === 0 && conditionIndex === 0 ? '(' : '',
                                field: condition.field,
                                operator: condition.operator,
                                value: condition.value,
                                valueTo: condition.valueTo || '',
                                daysOfWeek: condition.daysOfWeek || '',
                                closingBracket: conditionIndex === block.conditions.length - 1 ? ')' : '',
                                operatorList: condition.operatorList || [],
                                valueOptions: condition.valueOptions || [],
                                sqlType: condition.sqlType || '',
                                datetimeMode: condition.datetimeMode || 'date',
                                additionalOperatorId: condition.additionalOperatorId,
                                additionalTemplateId : condition.additionalTemplateId,
                                isIntervalOperator : condition.isIntervalOperator 
                            });
                        }
                    }
                    else
                    {
                        if (condition.field &&  condition.operator && (condition.value !== '' && condition.value !== null && condition.value !== undefined)) 
                        {
                            this.form.conditions.push({
                                relation: conditionIndex > 0 ? block.operator : (blockIndex > 0 ? (block.joinWithPrevious || 'OR') : ''),
                                openingBracket: blockIndex === 0 && conditionIndex === 0 ? '(' : '',
                                field: condition.field,
                                operator: condition.operator,
                                value: condition.value,
