                                additionalOperatorId: condition.additionalOperatorId,
                                additionalTemplateId : condition.additionalTemplateId,
                                isIntervalOperator : condition.isIntervalOperator 
                            });
                        }
                    }
                });
            });
        },
        loadSetupList : async function() {
            var vm = this;
            var params = `setupId=${vm.setupId}`;
            await locateBillingService.GetSetupList(params).then((response) => {
                if (response.data && response.data.result.setUpList.length>0) {
                    vm.setupList = response.data.result.setUpList;
                }
            }).catch((error) => {
                console.log('Error loading setup list:', error);
            });
        }
    },
};
</script>